record_types.code:
type AFRH_Register (As_Array : Boolean := False) is record
   case As_Array is
      when False =>
         Val : HAL.UInt32;
      when True =>
         Arr : AFRH_Field_Array;
   end case;
end record;

type AFRL_Register (As_Array : Boolean := False) is record
   case As_Array is
