   end case;
end record;

type BRR_Register is record
   BR : BRR_BR_Field := (As_Array => False, Val => 16#0#);
   Reserved_16_31 : HAL.UInt16 := 16#0#;
end record;

type BSRR_BR_Field (As_Array : Boolean := False) is record
